/* BTCommand — command palette / search menu.
 * Figma: D-Command 2461-2206 (web only).
 * Shared between Vue (BTCommand.vue) and React (BTCommand.tsx) — one file, zero duplication.
 */

/* ── Root container ──────────────────────────────────────────────────────── */

.bt-command {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 100%;
  background: var(--bg-primary);
  border: 1px solid var(--border-tertiary);
  border-radius: 12px;
  box-shadow: var(--shadow-elevation-md);
  overflow: hidden;
  font-family: var(--typography-font-family-sans);
}

/* ── Search area ─────────────────────────────────────────────────────────── */

.bt-command__search {
  padding: var(--space-sm);
  background: var(--bg-primary);
}

/* BTInputSearch inside command — remove validation row, fit command layout */
.bt-command__search .bt-input-search {
  width: 100%;
}

/* ── Separator ───────────────────────────────────────────────────────────── */

.bt-command__separator {
  height: 1px;
  background: var(--border-primary);
  border: none;
  margin: 0;
}

/* ── List ────────────────────────────────────────────────────────────────── */

.bt-command__list {
  max-height: 384px;
  overflow-y: auto;
  overscroll-behavior: contain;
}

/* ── Group ───────────────────────────────────────────────────────────────── */

.bt-command__group {
  padding: 6px var(--space-sm);
}

.bt-command__group-heading {
  padding: var(--space-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Empty ───────────────────────────────────────────────────────────────── */

.bt-command__empty {
  padding: var(--space-xl) var(--space-sm);
  text-align: center;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

/* ── Item ────────────────────────────────────────────────────────────────── */

.bt-command__item {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  padding: var(--space-sm);
  border-radius: var(--radius-xs);
  cursor: pointer;
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  user-select: none;
  transition: background-color 100ms ease;
  outline: none;
}

.bt-command__item:hover,
.bt-command__item--highlighted {
  background: var(--bg-subtle);
}

.bt-command__item[aria-disabled="true"] {
  opacity: 0.5;
  cursor: default;
  pointer-events: none;
}

.bt-command__item-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  color: var(--icon-primary);
}

.bt-command__item-icon > svg {
  width: 16px;
  height: 16px;
  display: block;
}

.bt-command__item-label {
  flex: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ── Shortcut ────────────────────────────────────────────────────────────── */

.bt-command__shortcut {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2xs);
  flex-shrink: 0;
  margin-inline-start: auto;
}

.bt-command__kbd {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 16px;
  min-width: 16px;
  padding: var(--space-2xs);
  background: var(--bg-subtle);
  border-radius: var(--radius-xs);
  font-size: var(--typography-font-size-2xs);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
  font-family: inherit;
}

/* ── Dialog backdrop ─────────────────────────────────────────────────────── */

.bt-command-dialog__backdrop {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding: 80px var(--space-lg) var(--space-lg);
  /* Raw rgba allowed (CLAUDE.md §6) — opacity overlay, not a named colour token. */
  background: rgba(0, 0, 0, 0.5);
  z-index: 9100;
}

.bt-command-dialog__panel {
  width: 100%;
  max-width: 500px;
}

/* ── Dialog transitions ──────────────────────────────────────────────────── */

.bt-command-dialog-enter-active,
.bt-command-dialog-leave-active {
  transition: opacity 150ms ease, transform 150ms ease;
}

.bt-command-dialog-enter-from,
.bt-command-dialog-leave-to {
  opacity: 0;
  transform: scale(0.97) translateY(-4px);
}

.bt-command-dialog-enter-to,
.bt-command-dialog-leave-from {
  opacity: 1;
  transform: scale(1) translateY(0);
}

/**
 * BTCommand — command palette / search menu (web only).
 * Figma: D-Command 2461-2206.
 *
 * Compound component — use sub-components to compose the palette:
 *   BTCommand, BTCommandInput, BTCommandList, BTCommandEmpty,
 *   BTCommandGroup, BTCommandItem, BTCommandSeparator,
 *   BTCommandShortcut, BTCommandDialog
 */
import type { InjectionKey, Ref } from 'vue';

/** Internal context shared between all sub-components via provide/inject. */
export interface BTCommandContext {
  /** Current search query (reactive). */
  query: Ref<string>;
  /** Value of the currently keyboard-highlighted item (null = none). */
  highlighted: Ref<string | null>;
  /** All registered item values in DOM insertion order. */
  itemValues: string[];
  /** Set of item values that are currently visible (match the query). */
  visibleSet: Set<string>;
  registerItem: (value: string) => void;
  unregisterItem: (value: string) => void;
  setItemVisible: (value: string, visible: boolean) => void;
  /** Shift the highlight up (-1) or down (+1) through visible items. */
  moveHighlight: (dir: 1 | -1) => void;
  /** Select the currently highlighted item. */
  selectHighlighted: () => void;
  /** Called when an item is activated (click or Enter). */
  onSelect: (value: string) => void;
}

export const BT_COMMAND_KEY: InjectionKey<BTCommandContext> =
  Symbol('BTCommandContext');

/** Props for the root BTCommand component. */
export interface BTCommandProps {
  /** Called when an item is selected. Receives the item's `value` string. */
  onSelect?: (value: string) => void;
}

/** Props for BTCommandInput. */
export interface BTCommandInputProps {
  /** Placeholder shown when the input is empty. */
  placeholder?: string;
}

/** Props for BTCommandGroup. */
export interface BTCommandGroupProps {
  /** Visible group heading text. */
  heading?: string;
}

/** Props for BTCommandItem. */
export interface BTCommandItemProps {
  /**
   * Unique value used for filtering and as the `onSelect` payload.
   * Should match the visible label text for best search results.
   */
  value: string;
  /** When true the item cannot be activated. */
  disabled?: boolean;
}

/** Props for BTCommandDialog. */
export interface BTCommandDialogProps {
  /** Controls dialog open state (v-model). */
  open: boolean;
  /**
   * Keyboard shortcut that opens the dialog globally.
   * Pass an empty string to disable. @default '⌘K'
   */
  shortcut?: string;
}

export { default as BTCommand } from './BTCommand.vue';
export { default as BTCommandInput } from './BTCommandInput.vue';
export { default as BTCommandList } from './BTCommandList.vue';
export { default as BTCommandEmpty } from './BTCommandEmpty.vue';
export { default as BTCommandGroup } from './BTCommandGroup.vue';
export { default as BTCommandItem } from './BTCommandItem.vue';
export { default as BTCommandSeparator } from './BTCommandSeparator.vue';
export { default as BTCommandShortcut } from './BTCommandShortcut.vue';
export { default as BTCommandDialog } from './BTCommandDialog.vue';
export type {
  BTCommandProps,
  BTCommandInputProps,
  BTCommandGroupProps,
  BTCommandItemProps,
  BTCommandDialogProps,
} from './BTCommand.types';
